import { SearchBar } from "./SearchBar";
import { Home } from "../pages/Home";
import { Songs } from "../pages/Songs";
import { Link } from "react-router-dom";

export const Navbar = () => {
    return(
        <div>
            <Link to="/" >Home</Link>
            <Link to="/songs" >Songs</Link>
            <Link to="/" >Home</Link>
            <Link to="/" >Home</Link>
        </div>
    );
}
